#!/usr/bin/env node
// Patches dist/server/wrangler.json (auto-generated by nitro's cloudflare-module
// preset on every build) with the asset-routing fields needed for this app:
//
// - not_found_handling: "single-page-application" — safety net only, for a
//   request that somehow reaches the Assets binding without a static file
//   match (e.g. the Worker itself erroring in a way that falls through).
//   With run_worker_first below sending virtually everything to the Worker
//   first, this should rarely if ever be what actually answers a request.
// - run_worker_first: routes every request to the Worker FIRST *except* the
//   negative (`!`-prefixed) patterns, which Cloudflare's Assets-with-Workers
//   routing sends straight to the Assets binding instead. This is the fix
//   for SSR metadata (title/description/canonical/OG/Twitter/JSON-LD) not
//   appearing in the initial HTML: previously only "/_serverFn/*" reached
//   the Worker, so Cloudflare served dist/client/index.html — a static,
//   generic shell with no per-route <head> — for every real page. Now every
//   navigational/document request (/, /landing, /notes, /admin/users,
//   /_serverFn/*, ...) runs through the Worker and gets TanStack Start's
//   real SSR output, while JS/CSS bundles, images, fonts, favicons,
//   robots.txt, sitemap.xml and the companion media library keep being
//   served directly by the Assets binding (cached, no Worker invocation).
//   Verified against the actual production build via `wrangler dev --local`
//   for both navigational routes (correct per-route SSR head) and static
//   assets (still 200 with correct content-type, CF-Cache-Status: HIT).
// - compatibility_date — nitro defaults this to today's date, which can be
//   newer than what the locally-installed wrangler/workerd binary supports
//   (observed: "newest date supported by this server binary" errors when the
//   sandbox clock is ahead of the installed version). Pinning it to a fixed,
//   known-good past date makes builds reproducible regardless of machine/CI
//   clock or wrangler version skew.
//
// WHY a postbuild patch instead of nitro config: @lovable.dev/vite-tanstack-config's
// `nitro.cloudflare` option type only allows { nodeCompat?, deployConfig? } —
// no `wrangler` passthrough — so the cleanest way to get these fields into the
// generated config without fighting that type is to patch the JSON directly
// after nitro writes it.

import { readFileSync, writeFileSync, existsSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, "..");
const wranglerPath = join(root, "dist/server/wrangler.json");

if (!existsSync(wranglerPath)) {
  console.error(
    `[patch-wrangler-assets] No file at ${wranglerPath} — did the nitro/Cloudflare build run? Skipping.`,
  );
  process.exit(1);
}

const config = JSON.parse(readFileSync(wranglerPath, "utf8"));

if (!config.assets) {
  console.error(
    "[patch-wrangler-assets] wrangler.json has no `assets` block — expected nitro's cloudflare-module preset to have generated one. Skipping.",
  );
  process.exit(1);
}

config.assets.not_found_handling = "single-page-application";
config.assets.run_worker_first = [
  "/**",
  "!/assets/**",
  "!/companions/**",
  "!/favicon.ico",
  "!/*.png",
  "!/*.webmanifest",
  "!/robots.txt",
  "!/sitemap.xml",
];
config.compatibility_date = "2025-09-24";

writeFileSync(wranglerPath, JSON.stringify(config, null, 2));
console.log("[patch-wrangler-assets] Patched dist/server/wrangler.json assets config");
